core_logic.pseudocode:
for rec in self:
    base = rec.order_id.request_inspection_date  # Date field → datetime.date
    if not base:
        rec.expected_date = False
        continue

    holiday_dates = self._get_public_holiday_dates(base.year)

    if rec.category == '1':
        days = 4
    elif rec.default_code == '4611001':
        days = 3
    else:
        days = 5

    rec.expected_date = self._add_working_days(base, days, holiday_dates)
